  .btn-primary:hover{transform:translateY(-2px);box-shadow:0 8px 32px rgba(0,212,255,.35);color:#0a0c12}
  .btn-secondary{
    background:transparent;color:var(--text);border:1px solid var(--border-light);
  }
  .btn-secondary:hover{border-color:var(--accent);color:var(--accent)}
  .btn-small{padding:8px 20px;font-size:.85rem}

  /* ── NAV ── */
  nav{
    position:fixed;top:0;left:0;right:0;z-index:100;height:var(--nav-h);
    background:rgba(10,12,18,.85);backdrop-filter:blur(16px);
    border-bottom:1px solid transparent;transition:border-color .3s;
  }
  nav.scrolled{border-bottom-color:var(--border)}
  nav .container{display:flex;align-items:center;justify-content:space-between;height:100%}
  .logo{display:flex;align-items:center;gap:10px;font-size:1.25rem;font-weight:700;color:#fff}
  .logo svg{flex-shrink:0}
  .nav-links{display:flex;align-items:center;gap:32px;list-style:none}
  .nav-links a{font-size:.9rem;color:var(--text-dim);transition:color .2s}
  .nav-links a:hover{color:#fff}
  .nav-cta .btn{padding:8px 22px;font-size:.85rem}
  .mobile-toggle{display:none;background:none;border:none;color:var(--text);cursor:pointer}

  /* ── HERO ── */
  .hero{
    padding-top:calc(var(--nav-h) + 80px);padding-bottom:80px;
    position:relative;overflow:hidden;
  }
  .hero::before{
    content:'';position:absolute;top:-200px;left:50%;transform:translateX(-50%);
    width:900px;height:500px;
    background:radial-gradient(ellipse,rgba(0,212,255,.07) 0%,transparent 70%);
    pointer-events:none;
  }
  .hero .container{display:grid;grid-template-columns:1fr 1fr;gap:64px;align-items:center}
  .hero-content .section-title{
    font-size:clamp(2rem,4.5vw,3.1rem);line-height:1.15;
    background:linear-gradient(135deg,#fff 40%,var(--accent));
    -webkit-background-clip:text;-webkit-text-fill-color:transparent;
    background-clip:text;
  }
  .hero-content .section-desc{margin-bottom:32px;max-width:480px}
  .hero-actions{display:flex;gap:16px;flex-wrap:wrap}

  /* Terminal */
  .terminal{
    background:#0d0f18;border:1px solid var(--border);border-radius:var(--radius-lg);
    overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.4),0 0 40px var(--accent-glow);
    position:relative;
  }
  .terminal-bar{
    display:flex;align-items:center;gap:8px;padding:12px 16px;
    background:#111420;border-bottom:1px solid var(--border);
  }
  .terminal-dot{width:12px;height:12px;border-radius:50%}
  .terminal-dot:nth-child(1){background:#ff5f57}
  .terminal-dot:nth-child(2){background:#febc2e}
  .terminal-dot:nth-child(3){background:#28c840}
  .terminal-title{margin-left:8px;font-size:.78rem;color:var(--text-muted);font-family:var(--mono)}
  .terminal-body{
    padding:16px;font-family:var(--mono);font-size:.78rem;line-height:1.8;
    height:380px;overflow:hidden;position:relative;
  }
  .terminal-body::after{
    content:'';position:absolute;bottom:0;left:0;right:0;height:60px;
    background:linear-gradient(transparent,#0d0f18);pointer-events:none;
  }
  .term-line{white-space:nowrap;opacity:0;animation:termFadeIn .4s ease forwards}
  .term-line .ts{color:var(--text-muted)}
  .term-line .level-info{color:var(--accent)}
  .term-line .level-warn{color:var(--yellow)}
  .term-line .level-error{color:var(--red)}
  .term-line .span{color:var(--accent2)}
  .term-line .val{color:var(--green)}
  .term-line .str{color:#ce9178}
  @keyframes termFadeIn{from{opacity:0;transform:translateY(4px)}to{opacity:1;transform:translateY(0)}}
  .term-cursor{
    display:inline-block;width:8px;height:16px;background:var(--accent);
    animation:blink .8s step-end infinite;vertical-align:text-bottom;margin-left:2px;
  }
  @keyframes blink{50%{opacity:0}}

  /* ── FEATURES ── */
  .features-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:32px;margin-top:48px}
  .feature-card{
    background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);
    padding:36px 28px;transition:all .35s ease;position:relative;overflow:hidden;
  }
  .feature-card::before{
    content:'';position:absolute;top:0;left:0;right:0;height:2px;
    background:linear-gradient(90deg,transparent,var(--accent),transparent);
    opacity:0;transition:opacity .35s;
  }
  .feature-card:hover{
    background:var(--bg-card-hover);transform:translateY(-4px);
    border-color:var(--border-light);box-shadow:0 12px 40px rgba(0,0,0,.3);
  }
  .feature-card:hover::before{opacity:1}
  .feature-icon{
    width:48px;height:48px;margin-bottom:20px;
    display:flex;align-items:center;justify-content:center;
    background:var(--accent-dim);border-radius:var(--radius);
  }
  .feature-card h3{font-size:1.15rem;font-weight:600;margin-bottom:10px}
  .feature-card p{font-size:.92rem;color:var(--text-dim);line-height:1.65}

  /* ── LOGOS ── */
  .logos-section{padding:48px 0;border-top:1px solid var(--border);border-bottom:1px solid var(--border)}
  .logos-section p{text-align:center;font-size:.85rem;color:var(--text-muted);margin-bottom:32px;letter-spacing:.04em}
  .logos-row{display:flex;align-items:center;justify-content:center;gap:56px;flex-wrap:wrap}
  .logo-item{
    opacity:.45;transition:opacity .3s;cursor:default;
    display:flex;align-items:center;gap:8px;color:var(--text-dim);
    font-weight:600;font-size:.95rem;letter-spacing:.02em;
  }
  .logo-item:hover{opacity:.8}
  .logo-item svg{height:28px;width:auto}

  /* ── TOUR ── */
  .tour-step{
    display:grid;grid-template-columns:1fr 1fr;gap:64px;align-items:center;
    padding:48px 0;border-bottom:1px solid var(--border);
  }
  .tour-step:last-child{border-bottom:none}
  .tour-step:nth-child(even){direction:rtl}
  .tour-step:nth-child(even)>.tour-text{direction:ltr}
  .tour-step:nth-child(even)>.tour-visual{direction:ltr}
  .tour-number{
    display:inline-flex;align-items:center;justify-content:center;
    width:32px;height:32px;border-radius:50%;
    background:var(--accent-dim);color:var(--accent);font-weight:700;font-size:.85rem;
    margin-bottom:16px;
  }
  .tour-text h3{font-size:1.3rem;font-weight:600;margin-bottom:10px}
  .tour-text p{color:var(--text-dim);line-height:1.7}

  /* Tour visuals */
  .tour-visual{
    background:var(--bg-elevated);border:1px solid var(--border);border-radius:var(--radius-lg);
    padding:24px;position:relative;min-height:280px;
  }
  /* Step 1: Dashboard mock */
  .dash-mock{display:flex;flex-direction:column;gap:12px}
  .dash-header{display:flex;justify-content:space-between;align-items:center}
  .dash-header span{font-size:.8rem;color:var(--text-dim)}
  .dash-header .badge{
    font-size:.7rem;padding:2px 10px;border-radius:99px;
    background:rgba(0,230,118,.12);color:var(--green);font-weight:600;
  }
  .dash-bars{display:flex;align-items:flex-end;gap:6px;height:120px;padding-top:12px}
  .dash-bar{
    flex:1;border-radius:3px 3px 0 0;background:linear-gradient(to top,var(--accent),rgba(0,212,255,.3));
    transition:height .6s ease;
  }
  .dash-bar:nth-child(odd){background:linear-gradient(to top,var(--accent2),rgba(108,92,231,.3))}
  .dash-metrics{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}
  .dash-metric{
    background:var(--bg-card);border-radius:var(--radius);padding:10px 12px;text-align:center;
  }
  .dash-metric .num{font-size:1.1rem;font-weight:700;color:var(--accent)}
  .dash-metric .label{font-size:.65rem;color:var(--text-muted);margin-top:2px}

  /* Step 2: Trace view */
  .trace-mock{display:flex;flex-direction:column;gap:8px}
  .trace-header{font-size:.78rem;color:var(--text-dim);display:flex;justify-content:space-between}
  .trace-row{display:flex;align-items:center;gap:8px;font-size:.75rem;font-family:var(--mono)}
  .trace-row .dot{width:8px;height:8px;border-radius:50%;flex-shrink:0}
  .trace-row .dot.green{background:var(--green)}
  .trace-row .dot.yellow{background:var(--yellow)}
  .trace-row .dot.red{background:var(--red)}
  .trace-bar{
    height:20px;border-radius:3px;position:relative;flex:1;
    display:flex;align-items:center;padding:0 8px;font-size:.65rem;
  }
  .trace-bar.inbound{background:rgba(0,212,255,.15);color:var(--accent)}
  .trace-bar.process{background:rgba(108,92,231,.15);color:var(--accent2)}
  .trace-bar.outbound{background:rgba(0,230,118,.15);color:var(--green)}
  .trace-bar.latency{background:rgba(255,82,82,.15);color:var(--red)}
  .trace-timeline{display:flex;gap:2px;margin-top:8px}
  .trace-tick{flex:1;height:2px;background:var(--border);border-radius:1px}
  .trace-tick.active{background:var(--accent)}

  /* Step 3: Alert */
  .alert-mock{display:flex;flex-direction:column;gap:12px}
  .alert-card{
    background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius);
    padding:14px 16px;display:flex;align-items:center;gap:12px;
    border-left:3px solid var(--accent);
  }
  .alert-card.warn{border-left-color:var(--yellow)}
  .alert-card.error{border-left-color:var(--red)}
  .alert-icon{flex-shrink:0}
  .alert-body .alert-title{font-size:.82rem;font-weight:600;margin-bottom:2px}
  .alert-body .alert-msg{font-size:.72rem;color:var(--text-muted)}
  .alert-time{font-size:.68rem;color:var(--text-muted);margin-left:auto;white-space:nowrap}

  /* Step 4: Integration */
  .integration-mock{display:flex;flex-direction:column;align-items:center;gap:20px}
  .int-center{
    width:80px;height:80px;border-radius:50%;
    background:linear-gradient(135deg,var(--accent),var(--accent2));
    display:flex;align-items:center;justify-content:center;
    font-weight:700;color:#0a0c12;font-size:.75rem;
    box-shadow:0 0 30px rgba(0,212,255,.3);
    position:relative;z-index:2;
  }
  .int-nodes{display:flex;gap:24px;flex-wrap:wrap;justify-content:center}
  .int-node{
    padding:8px 16px;border-radius:var(--radius);font-size:.72rem;font-weight:600;
    border:1px solid var(--border);background:var(--bg-card);color:var(--text-dim);
    display:flex;align-items:center;gap:6px;
  }
  .int-node .int-dot{width:6px;height:6px;border-radius:50%}
  .int-connections{
    position:absolute;top:50%;left:50%;width:280px;height:280px;
    transform:translate(-50%,-50%);border:1px dashed var(--border);border-radius:50%;
    pointer-events:none;
  }

  /* ── PRICING ── */
  .pricing-teaser{
    text-align:center;padding:80px 0;
    background:linear-gradient(180deg,var(--bg) 0%,var(--bg-elevated) 50%,var(--bg) 100%);
  }
  .pricing-cards{display:grid;grid-template-columns:repeat(3,1fr);gap:24px;margin-top:48px;max-width:800px;margin-left:auto;margin-right:auto}
  .pricing-card{
    background:var(--bg-card);border:1px solid var(--border);border-radius:var(--radius-lg);
    padding:32px 24px;transition:all .35s;position:relative;
  }
  .pricing-card.featured{border-color:var(--accent);box-shadow:0 0 30px var(--accent-glow)}
  .pricing-card.featured::after{
    content:'POPULAR';position:absolute;top:-10px;left:50%;transform:translateX(-50%);
    font-size:.65rem;font-weight:700;letter-spacing:.1em;padding:3px 12px;
    background:var(--accent);color:#0a0c12;border-radius:99px;
  }
  .pricing-card:hover{transform:translateY(-4px);border-color:var(--border-light)}
  .pricing-card .plan-name{font-size:.9rem;color:var(--text-dim);margin-bottom:8px}
  .pricing-card .plan-price{font-size:2rem;font-weight:700;margin-bottom:4px}
  .pricing-card .plan-price span{font-size:.9rem;font-weight:400;color:var(--text-muted)}
  .pricing-card .plan-desc{font-size:.82rem;color:var(--text-muted);margin-bottom:20px}
  .pricing-card ul{list-style:none;text-align:left;margin-bottom:24px}
  .pricing-card li{font-size:.82rem;color:var(--text-dim);padding:6px 0;display:flex;align-items:center;gap:8px}
  .pricing-card li::before{content:'✓';color:var(--green);font-weight:700;font-size:.75rem}

  /* ── FOOTER ── */
  footer{padding:64px 0 32px;border-top:1px solid var(--border)}
  .footer-grid{display:grid;grid-template-columns:2fr repeat(3,1fr);gap:48px;margin-bottom:48px}
  .footer-brand{display:flex;flex-direction:column;gap:12px}
  .footer-brand .desc{font-size:.85rem;color:var(--text-muted);max-width:260px;line-height:1.6}
  .footer-col h4{font-size:.8rem;text-transform:uppercase;letter-spacing:.1em;color:var(--text-muted);margin-bottom:16px;font-weight:600}
  .footer-col ul{list-style:none}
  .footer-col li{margin-bottom:10px}
  .footer-col a{font-size:.88rem;color:var(--text-dim);transition:color .2s}
  .footer-col a:hover{color:var(--accent)}
  .footer-bottom{
    display:flex;justify-content:space-between;align-items:center;
    padding-top:24px;border-top:1px solid var(--border);
    font-size:.8rem;color:var(--text-muted);
  }
  .status-badge{
    display:inline-flex;align-items:center;gap:6px;padding:4px 14px;
    border-radius:99px;background:rgba(0,230,118,.08);color:var(--green);font-size:.78rem;font-weight:600;
  }
  .status-dot{width:7px;height:7px;border-radius:50%;background:var(--green);animation:pulse 2s ease infinite}
  @keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}

  /* ── RESPONSIVE ── */
  @media(max-width:900px){
    .hero .container{grid-template-columns:1fr;text-align:center}
    .hero-content .section-desc{margin-left:auto;margin-right:auto}
    .hero-actions{justify-content:center}
    .terminal{max-width:520px;margin:0 auto}
    .features-grid{grid-template-columns:1fr}
    .tour-step{grid-template-columns:1fr;gap:32px}
    .tour-step:nth-child(even){direction:ltr}
    .pricing-cards{grid-template-columns:1fr;max-width:360px}
    .footer-grid{grid-template-columns:1fr 1fr}
    .nav-links{display:none}
    .mobile-toggle{display:block}
  }
  @media(max-width:600px){
    .logos-row{gap:28px}
    .footer-grid{grid-template-columns:1fr}
    .footer-bottom{flex-direction:column;gap:12px;text-align:center}
  }
</style>
</head>
<body>

