<!-- ════════════════ FEATURES ════════════════ -->
<section class="section" id="features">
  <div class="container">
    <div style="text-align:center;margin-bottom:16px" class="reveal">
      <span class="section-label">Why teams switch</span>
    </div>
    <h2 class="section-title reveal" style="text-align:center">Built for the way modern pipelines actually run</h2>
    <p class="section-desc reveal" style="text-align:center;margin:0 auto">
      Existing observability tools were designed for request/response systems. Streaming pipelines need a different kind of tracing — one that follows state, not just HTTP calls.
    </p>

    <div class="features-grid">
      <!-- Feature 1 -->
      <div class="feature-card reveal reveal-delay-1">
        <div class="feature-icon">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
            <circle cx="12" cy="12" r="3" stroke="#00d4ff" stroke-width="1.5"/>
            <path d="M12 2v4M12 18v4M2 12h4M18 12h4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83" stroke="#00d4ff" stroke-width="1.5" stroke-linecap="round"/>
          </svg>
        </div>
        <h3>End-to-end message tracing</h3>
        <p>Follow a single event from the producer through every consumer group, state store, and sink — with per-stage latency and error attribution.</p>
      </div>

      <!-- Feature 2 -->
      <div class="feature-card reveal reveal-delay-2">
        <div class="feature-icon">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
            <rect x="3" y="3" width="7" height="7" rx="1.5" stroke="#6c5ce7" stroke-width="1.5"/>
            <rect x="14" y="3" width="7" height="7" rx="1.5" stroke="#6c5ce7" stroke-width="1.5" opacity=".6"/>
            <rect x="3" y="14" width="7" height="7" rx="1.5" stroke="#6c5ce7" stroke-width="1.5" opacity=".6"/>
            <rect x="14" y="14" width="7" height="7" rx="1.5" stroke="#6c5ce7" stroke-width="1.5"/>
            <path d="M10 6.5h4M6.5 10v4M17.5 10v4M10 17.5h4" stroke="#6c5ce7" stroke-width="1.2" stroke-linecap="round"/>
          </svg>
        </div>
        <h3>State-aware correlation</h3>
        <p>Helix understands windowed aggregations, side inputs, and stateful transforms. Trace lines connect to the exact state key and partition responsible.</p>
      </div>

      <!-- Feature 3 -->
      <div class="feature-card reveal reveal-delay-3">
        <div class="feature-icon">
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
            <path d="M12 2L2 7l10 5 10-5-10-5z" stroke="#00d4ff" stroke-width="1.5" stroke-linejoin="round"/>
            <path d="M2 17l10 5 10-5" stroke="#00d4ff" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
            <path d="M2 12l10 5 10-5" stroke="#00d4ff" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" opacity=".5"/>
          </svg>
        </div>
        <h3>Zero-config instrumentation</h3>
        <p>Drop in our agent library and Helix auto-instruments Kafka brokers, Flink jobs, and Spark executors. No code changes, no annotation hell.</p>
      </div>
    </div>
  </div>
</section>

<!-- ════════════════ LOGOS ════════════════ -->
<section class="logos-section">
  <div class="container">
    <p>Trusted by engineering teams at</p>
    <div class="logos-row">
      <div class="logo-item">
        <svg viewBox="0 0 36 28" fill="none"><rect width="36" height="28" rx="4" fill="#1e2235"/><path d="M10 8h16M10 14h12M10 20h8" stroke="#8a90a8" stroke-width="1.5" stroke-linecap="round"/></svg>
