  /* ── Content ── */
  .content{padding:24px}
  .content-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:20px}
  .content-header h2{font-size:1.1rem;font-weight:600}
  .last-updated{font-size:.8rem;color:var(--text-tertiary)}

  /* ── KPI Strip ── */
  .kpi-strip{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:24px}
  .kpi-card{background:var(--bg-white);border:1px solid var(--border);border-radius:var(--radius);padding:18px 20px;
    transition:all var(--transition)}
  .kpi-card:hover{box-shadow:var(--shadow-md);border-color:var(--emerald)}
  .kpi-label{font-size:.78rem;font-weight:600;text-transform:uppercase;letter-spacing:.04em;color:var(--text-secondary);margin-bottom:6px}
  .kpi-value{font-size:1.75rem;font-weight:700;color:var(--text);line-height:1.2;margin-bottom:4px}
  .kpi-delta{font-size:.78rem;font-weight:500;display:flex;align-items:center;gap:3px}
  .kpi-delta.up{color:var(--red)}
  .kpi-delta.down{color:var(--emerald)}
  .sparkline-wrap{margin-top:10px;height:32px}
  .sparkline-wrap svg{width:100%;height:100%}

  /* ── Chart Section ── */
  .chart-section{background:var(--bg-white);border:1px solid var(--border);border-radius:var(--radius);padding:20px;margin-bottom:24px}
  .chart-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:16px}
  .chart-header h3{font-size:1rem;font-weight:600}
  .chart-legend{display:flex;gap:16px}
  .legend-item{display:flex;align-items:center;gap:6px;font-size:.78rem;color:var(--text-secondary)}
  .legend-dot{width:10px;height:3px;border-radius:2px}
  .chart-container{position:relative;width:100%;height:300px}
  .chart-container svg{width:100%;height:100%}
  .tooltip{position:absolute;pointer-events:none;background:var(--text);color:#fff;padding:8px 12px;
    border-radius:var(--radius-sm);font-size:.78rem;box-shadow:var(--shadow-md);opacity:0;
    transition:opacity 150ms;z-index:10;line-height:1.6;white-space:nowrap}
  .tooltip.visible{opacity:1}

  /* ── Table ── */
  .table-section{background:var(--bg-white);border:1px solid var(--border);border-radius:var(--radius);overflow:hidden}
  .table-header{display:flex;align-items:center;justify-content:space-between;padding:16px 20px;border-bottom:1px solid var(--border)}
  .table-header h3{font-size:1rem;font-weight:600}
  .table-wrap{overflow-x:auto}
  table{width:100%;border-collapse:collapse}
  thead{background:var(--bg)}
  th{padding:10px 16px;text-align:left;font-size:.78rem;font-weight:600;text-transform:uppercase;letter-spacing:.04em;
    color:var(--text-secondary);border-bottom:1px solid var(--border);cursor:pointer;user-select:none;
    white-space:nowrap;transition:color var(--transition)}
  th:hover{color:var(--emerald)}
  th.sorted{color:var(--emerald)}
  th .sort-icon{margin-left:4px;font-size:.7rem;opacity:.4}
  th.sorted .sort-icon{opacity:1}
  td{padding:12px 16px;border-bottom:1px solid var(--border-light);font-size:.88rem;vertical-align:middle}
  tr:last-child td{border-bottom:none}
  tr:hover td{background:var(--bg-hover)}
  .service-name{font-weight:600;color:var(--text)}
  .status-pill{display:inline-flex;align-items:center;gap:5px;padding:3px 10px;border-radius:99px;font-size:.75rem;font-weight:600}
  .status-pill.healthy{background:var(--emerald-light);color:var(--emerald-dark)}
  .status-pill.degraded{background:var(--yellow-light);color:#92400e}
  .status-pill.critical{background:var(--red-light);color:#991b1b}
  .status-dot{width:6px;height:6px;border-radius:50%;background:currentColor}
  .latency-val{font-family:"SF Mono",SFMono-Regular,Consolas,"Liberation Mono",Menlo,monospace;font-size:.85rem}
  .error-rate-bar{display:flex;align-items:center;gap:8px}
  .error-bar-track{width:60px;height:5px;background:var(--bg);border-radius:99px;overflow:hidden}
  .error-bar-fill{height:100%;border-radius:99px;background:var(--emerald);transition:width .3s}
  .error-bar-fill.warn{background:var(--yellow)}
  .error-bar-fill.bad{background:var(--red)}
  .deploy-time{font-size:.82rem;color:var(--text-secondary)}
</style>
</head>
