<script>
// ── Data ──
const services = [
  { name:"api-gateway", status:"healthy", p99:187, error:0.84, deploy:"2h ago" },
  { name:"auth-service", status:"healthy", p99:42, error:0.12, deploy:"1d ago" },
  { name:"user-service", status:"healthy", p99:65, error:0.31, deploy:"6h ago" },
  { name:"order-service", status:"degraded", p99:312, error:2.47, deploy:"30m ago" },
  { name:"payment-service", status:"healthy", p99:98, error:0.55, deploy:"12h ago" },
  { name:"inventory-service", status:"healthy", p99:54, error:0.22, deploy:"3d ago" },
  { name:"notification-service", status:"healthy", p99:33, error:0.08, deploy:"1w ago" },
  { name:"search-service", status:"degraded", p99:245, error:1.89, deploy:"45m ago" },
  { name:"analytics-service", status:"healthy", p99:128, error:0.44, deploy:"8h ago" },
  { name:"cache-service", status:"healthy", p99:8, error:0.01, deploy:"2w ago" },
  { name:"queue-worker", status:"critical", p99:489, error:5.21, deploy:"15m ago" },
  { name:"cdn-proxy", status:"healthy", p99:15, error:0.03, deploy:"5d ago" }
];

// Generate 24h sample data (every hour)
function genData(base, variance, n=24){
  const d=[];
  let v=base;
  for(let i=0;i<n;i++){
    v+=(Math.random()-0.45)*variance;
    v=Math.max(base*0.4, Math.min(base*1.8, v));
    d.push(Math.round(v));
  }
  return d;
}
const p99Data = genData(180, 30);
const p50Data = genData(38, 8);
const errorData = genData(0.8, 0.3).map(v=>Math.round(v*100)/100);
const flightData = genData(1200, 120);

// ── Sparklines ──
function drawSparkline(containerId, data, color){
  const c=document.getElementById(containerId);
  const w=c.clientWidth||200, h=32;
  const pad=2;
  const mn=Math.min(...data), mx=Math.max(...data), range=mx-mn||1;
  const pts=data.map((v,i)=>({
    x: pad+(i/(data.length-1))*(w-2*pad),
    y: pad+(1-(v-mn)/range)*(h-2*pad)
  }));
  let pathD=pts.map((p,i)=>(i?'L':'M')+p.x+','+p.y).join(' ');
  let areaD=pathD+` L${pts[pts.length-1].x},${h} L${pts[0].x},${h} Z`;
  c.innerHTML=`<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none">
    <defs><linearGradient id="g${containerId}" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="${color}" stop-opacity=".18"/>
      <stop offset="100%" stop-color="${color}" stop-opacity=".02"/>
    </linearGradient></defs>
    <path d="${areaD}" fill="url(#g${containerId})"/>
    <path d="${pathD}" fill="none" stroke="${color}" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/>
  </svg>`;
}
drawSparkline('spark-p50', p50Data, '#10b981');
drawSparkline('spark-p99', p99Data, '#10b981');
drawSparkline('spark-errors', errorData, '#f59e0b');
drawSparkline('spark-flight', flightData, '#3b82f6');

// ── Main Chart ──
function drawMainChart(){
  const container=document.getElementById('chart-container');
  const rect=container.getBoundingClientRect();
  const W=rect.width, H=rect.height;
  const pad={top:20,right:20,bottom:40,left:50};
  const cw=W-pad.left-pad.right, ch=H-pad.top-pad.bottom;

  const allVals=[...p99Data,...p50Data];
  const mn=0, mx=Math.ceil(Math.max(...allVals)/50)*50+50;

  const xScale=i=>pad.left+(i/(p99Data.length-1))*cw;
  const yScale=v=>pad.top+(1-(v-mn)/(mx-mn))*ch;

  const hourLabels=[];
  for(let i=0;i<24;i+=2) hourLabels.push(i+'h');

  let svgParts=[];
  // Gridlines
  const yTicks=[];
  for(let v=0;v<=mx;v+=50) yTicks.push(v);
  yTicks.forEach(v=>{
    const y=yScale(v);
    svgParts.push(`<line x1="${pad.left}" y1="${y}" x2="${W-pad.right}" y2="${y}" stroke="#e2e8f0" stroke-width="1"/>`);
    svgParts.push(`<text x="${pad.left-8}" y="${y+4}" text-anchor="end" fill="#94a3b8" font-size="11" font-family="inherit">${v}</text>`);
  });
  // X labels
  hourLabels.forEach((l,i)=>{
    const x=xScale(i*2);
    svgParts.push(`<line x1="${x}" y1="${pad.top}" x2="${x}" y2="${H-pad.bottom}" stroke="#e2e8f0" stroke-width="1"/>`);
    svgParts.push(`<text x="${x}" y="${H-pad.bottom+20}" text-anchor="middle" fill="#94a3b8" font-size="11" font-family="inherit">${l}</text>`);
  });

  // Area + lines
  function makePath(data){
    return data.map((v,i)=>(i?'L':'M')+xScale(i)+','+yScale(v)).join(' ');
  }
  function makeArea(data){
    const p=makePath(data);
    return p+` L${xScale(data.length-1)},${yScale(mn)} L${xScale(0)},${yScale(mn)} Z`;
  }

  svgParts.push(`<defs>
    <linearGradient id="g99" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="#10b981" stop-opacity=".12"/>
      <stop offset="100%" stop-color="#10b981" stop-opacity=".01"/>
    </linearGradient>
    <linearGradient id="g50" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="#3b82f6" stop-opacity=".08"/>
      <stop offset="100%" stop-color="#3b82f6" stop-opacity=".01"/>
    </linearGradient>
  </defs>`);
  svgParts.push(`<path d="${makeArea(p99Data)}" fill="url(#g99)"/>`);
  svgParts.push(`<path d="${makeArea(p50Data)}" fill="url(#g50)"/>`);
  svgParts.push(`<path d="${makePath(p99Data)}" fill="none" stroke="#10b981" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" class="chart-line"/>`);
  svgParts.push(`<path d="${makePath(p50Data)}" fill="none" stroke="#3b82f6" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="chart-line"/>`);

  // Interactive overlay
  svgParts.push(`<rect x="${pad.left}" y="${pad.top}" width="${cw}" height="${ch}" fill="transparent" class="chart-overlay"/>`);

  // Vertical hover line (hidden by default)
  svgParts.push(`<line x1="0" y1="${pad.top}" x2="0" y2="${H-pad.bottom}" stroke="#cbd5e1" stroke-width="1" stroke-dasharray="4 3" class="hover-line" style="display:none"/>`);
  // Dots
  svgParts.push(`<circle r="5" fill="#10b981" stroke="#fff" stroke-width="2" class="hover-dot-99" style="display:none"/>`);
  svgParts.push(`<circle r="4" fill="#3b82f6" stroke="#fff" stroke-width="2" class="hover-dot-50" style="display:none"/>`);

  container.innerHTML=`<div class="tooltip" id="tooltip"></div><svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="none">${svgParts.join('\n')}</svg>`;

  // Hover interaction
  const overlay=container.querySelector('.chart-overlay');
  const hoverLine=container.querySelector('.hover-line');
  const dot99=container.querySelector('.hover-dot-99');
  const dot50=container.querySelector('.hover-dot-50');
  const tooltip=document.getElementById('tooltip');

  overlay.addEventListener('mousemove',e=>{
    const svgRect=container.querySelector('svg').getBoundingClientRect();
    const mx=e.clientX-svgRect.left;
    const relX=(mx-pad.left)/cw;
    const idx=Math.round(relX*(p99Data.length-1));
    if(idx<0||idx>=p99Data.length) return;

    const cx=xScale(idx);
    hoverLine.setAttribute('x1',cx);
    hoverLine.setAttribute('x2',cx);
    hoverLine.style.display='';

    dot99.setAttribute('cx',cx);
    dot99.setAttribute('cy',yScale(p99Data[idx]));
    dot99.style.display='';

    dot50.setAttribute('cx',cx);
    dot50.setAttribute('cy',yScale(p50Data[idx]));
    dot50.style.display='';

    tooltip.innerHTML=`<strong>${idx}h ago</strong><br>P99: ${p99Data[idx]} ms<br>P50: ${p50Data[idx]} ms`;
    tooltip.classList.add('visible');

    let tx=cx+12, ty=yScale(p99Data[idx])-30;
    if(tx+140>W) tx=cx-150;
    if(ty<10) ty=10;
    tooltip.style.left=tx+'px';
    tooltip.style.top=ty+'px';
  });

  overlay.addEventListener('mouseleave',()=>{
    hoverLine.style.display='none';
    dot99.style.display='none';
    dot50.style.display='none';
    tooltip.classList.remove('visible');
  });
}
drawMainChart();
window.addEventListener('resize',()=>{clearTimeout(window._rt);window._rt=setTimeout(drawMainChart,150)});

// ── Table ──
let sortCol=-1, sortAsc=true;
function renderTable(data){
  const tb=document.getElementById('service-tbody');
  tb.innerHTML=data.map(s=>{
    const errClass=s.error>2?'bad':s.error>1?'warn':'';
    const barW=Math.min(100,s.error*15);
    return `<tr>
      <td class="service-name">${s.name}</td>
      <td><span class="status-pill ${s.status}"><span class="status-dot"></span>${s.status.charAt(0).toUpperCase()+s.status.slice(1)}</span></td>
      <td class="latency-val">${s.p99} ms</td>
      <td>
        <div class="error-rate-bar">
          <span class="latency-val">${s.error}%</span>
          <div class="error-bar-track"><div class="error-bar-fill ${errClass}" style="width:${barW}%"></div></div>
        </div>
      </td>
      <td class="deploy-time">${s.deploy}</td>
    </tr>`;
  }).join('');
}
renderTable(services);

function sortTable(col){
  if(sortCol===col) sortAsc=!sortAsc; else {sortCol=col;sortAsc=true;}
