let sortCol=-1, sortAsc=true;
function renderTable(data){
  const tb=document.getElementById('service-tbody');
  tb.innerHTML=data.map(s=>{
    const errClass=s.error>2?'bad':s.error>1?'warn':'';
    const barW=Math.min(100,s.error*15);
    return `<tr>
      <td class="service-name">${s.name}</td>
      <td><span class="status-pill ${s.status}"><span class="status-dot"></span>${s.status.charAt(0).toUpperCase()+s.status.slice(1)}</span></td>
      <td class="latency-val">${s.p99} ms</td>
      <td>
        <div class="error-rate-bar">
          <span class="latency-val">${s.error}%</span>
          <div class="error-bar-track"><div class="error-bar-fill ${errClass}" style="width:${barW}%"></div></div>
        </div>
      </td>
      <td class="deploy-time">${s.deploy}</td>
    </tr>`;
  }).join('');
}
renderTable(services);

function sortTable(col){
  if(sortCol===col) sortAsc=!sortAsc; else {sortCol=col;sortAsc=true;}
  const keys=['name','status','p99','error','deploy'];
  const k=keys[col];
  services.sort((a,b)=>{
    if(typeof a[k]==='string') return sortAsc?a[k].localeCompare(b[k]):b[k].localeCompare(a[k]);
    return sortAsc?a[k]-b[k]:b[k]-a[k];
  });
  renderTable(services);
  // Update header styles
  document.querySelectorAll('#service-table th').forEach(th=>{
    th.classList.toggle('sorted',+th.dataset.col===col);
    const icon=th.querySelector('.sort-icon');
    if(icon) icon.textContent=+th.dataset.col===col?(sortAsc?'↑':'↓'):'⇅';
  });
}

// ── Sidebar Toggle ──
