      const items = [...document.querySelectorAll('.faq-question')];
      const idx = items.indexOf(e.target);
      let newIdx;
      if (e.key === 'ArrowDown') newIdx = (idx + 1) % items.length;
      if (e.key === 'ArrowUp') newIdx = (idx - 1 + items.length) % items.length;
      if (newIdx !== undefined) {
        e.preventDefault();
        items[newIdx].focus();
      }
    }
    // Toggle toggle with space/enter
    if (e.target === toggle && (e.key === ' ' || e.key === 'Enter')) {
