<script>
  // ── BILLING TOGGLE ──
  const toggle = document.getElementById('billing-toggle');
  const monthlyLabel = document.getElementById('monthly-label');
  const annualLabel = document.getElementById('annual-label');
  const priceStarter = document.getElementById('price-starter');
  const priceTeam = document.getElementById('price-team');
  const periodTeam = document.getElementById('period-team');
  const noteTeam = document.getElementById('note-team');

  let isAnnual = false;

  function animatePrice(el, newVal) {
    el.classList.add('animating');
    setTimeout(() => {
      el.textContent = newVal;
      el.classList.remove('animating');
    }, 200);
  }

  toggle.addEventListener('click', () => {
    isAnnual = !isAnnual;
    toggle.classList.toggle('active', isAnnual);
    toggle.setAttribute('aria-checked', isAnnual);
    monthlyLabel.classList.toggle('active', !isAnnual);
    annualLabel.classList.toggle('active', isAnnual);

    // Starter stays $0
    // Team: $29 -> $23
    if (isAnnual) {
      animatePrice(priceTeam, '23');
      periodTeam.textContent = '/mo per user';
      noteTeam.innerHTML = 'Billed annually <span class="annual-badge">Save 20%</span>';
    } else {
      animatePrice(priceTeam, '29');
      periodTeam.textContent = '/mo per user';
      noteTeam.textContent = 'Billed monthly';
    }
  });

  // ── COMPARISON TABLE COLLAPSE ──
  function toggleCategory(row) {
    const category = row.dataset.category;
    const isCollapsed = row.classList.toggle('collapsed');
    document.querySelectorAll(`.category-body[data-category="${category}"]`).forEach(el => {
      el.classList.toggle('hidden', isCollapsed);
    });
  }

  // ── FAQ ACCORDION ──
  function toggleFaq(btn) {
    const item = btn.closest('.faq-item');
    const isOpen = item.classList.contains('open');

    // Close all others
    document.querySelectorAll('.faq-item.open').forEach(el => {
      if (el !== item) {
        el.classList.remove('open');
        el.querySelector('.faq-question').setAttribute('aria-expanded', 'false');
      }
    });

    // Toggle current
    item.classList.toggle('open', !isOpen);
    btn.setAttribute('aria-expanded', !isOpen);
  }

  // ── KEYBOARD ACCESSIBILITY ──
  document.addEventListener('keydown', (e) => {
    // Arrow key navigation for FAQ
    if (e.target.classList.contains('faq-question')) {
      const items = [...document.querySelectorAll('.faq-question')];
      const idx = items.indexOf(e.target);
      let newIdx;
      if (e.key === 'ArrowDown') newIdx = (idx + 1) % items.length;
      if (e.key === 'ArrowUp') newIdx = (idx - 1 + items.length) % items.length;
      if (newIdx !== undefined) {
        e.preventDefault();
        items[newIdx].focus();
      }
    }
    // Toggle toggle with space/enter
    if (e.target === toggle && (e.key === ' ' || e.key === 'Enter')) {
      e.preventDefault();
      toggle.click();
    }
  });
</script>
