<body>
<canvas id="c"></canvas>
<script>
(() => {
  const canvas = document.getElementById('c');
  const ctx = canvas.getContext('2d');

  const N = 3000;
  const TRAIL_ALPHA = 0.045;
  const DAMPING = 0.97;
  const ATTRACTION = 0.012;
  const REPULSION_DIST = 18;
  const REPULSION_STR = 0.0008;
  const MAX_VEL = 4;
  const PARTICLE_SIZE = 1.2;
  const HUE_CENTER = 200;
  const HUE_SPREAD = 40;
  const SATURATION = 85;
  const LIGHTNESS = 60;

  let particles = [];
  let target = { x: 0, y: 0 };
  let mouseActive = false;
  let width, height;
  let dpr;

  function createParticles() {
    const arr = new Float32Array(N * 4);
    for (let i = 0; i < N; i++) {
      const idx = i * 4;
      arr[idx]     = Math.random() * width;
      arr[idx + 1] = Math.random() * height;
      arr[idx + 2] = (Math.random() - 0.5) * 2;
      arr[idx + 3] = (Math.random() - 0.5) * 2;
    }
    return arr;
  }

  function resize() {
    dpr = window.devicePixelRatio || 1;
    width = window.innerWidth;
    height = window.innerHeight;
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    canvas.style.width = width + 'px';
    canvas.style.height = height + 'px';
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    target.x = width / 2;
    target.y = height / 2;
    ctx.fillStyle = '#000';
    ctx.fillRect(0, 0, width, height);
    particles = createParticles();
  }

  function update() {
    const cx = width / 2;
    const cy = height / 2;

    for (let i = 0; i < N; i++) {
      const idx = i * 4;
      let px = particles[idx];
      let py = particles[idx + 1];
      let vx = particles[idx + 2];
      let vy = particles[idx + 3];

      // Attraction to target
      const dx = target.x - px;
      const dy = target.y - py;
      const distSq = dx * dx + dy * dy + 1;
      const dist = Math.sqrt(distSq);
      const force = ATTRACTION / (1 + dist * 0.005);
      vx += dx / dist * force;
      vy += dy / dist * force;

      // Subtle repulsion from other particles (sample a subset for perf)
      if (i % 3 === 0) {
        for (let j = i + 1; j < N && j < i + 60; j++) {
          const jdx = px - particles[j * 4];
          const jdy = py - particles[j * 4 + 1];
          const jsq = jdx * jdx + jdy * jdy;
          if (jsq < REPULSION_DIST * REPULSION_DIST && jsq > 0.01) {
            const jf = REPULSION_STR / jsq;
            vx += jdx * jf;
            vy += jdy * jf;
          }
        }
      }

      // Damping
      vx *= DAMPING;
      vy *= DAMPING;

      // Clamp velocity
      const speed = Math.sqrt(vx * vx + vy * vy);
      if (speed > MAX_VEL) {
        const inv = MAX_VEL / speed;
        vx *= inv;
        vy *= inv;
      }

      // Update position
      px += vx;
      py += vy;

      // Soft boundary wrapping
      const margin = 50;
      if (px < -margin) px = width + margin;
      if (px > width + margin) px = -margin;
      if (py < -margin) py = height + margin;
      if (py > height + margin) py = -margin;

      particles[idx]     = px;
      particles[idx + 1] = py;
      particles[idx + 2] = vx;
      particles[idx + 3] = vy;
    }
  }

  function draw() {
    // Trail fade
    ctx.globalCompositeOperation = 'source-over';
    ctx.fillStyle = `rgba(0, 0, 0, ${TRAIL_ALPHA})`;
    ctx.fillRect(0, 0, width, height);

    // Additive blending for glow
    ctx.globalCompositeOperation = 'lighter';

    const step = N > 2000 ? 1 : 1;
    for (let i = 0; i < N; i += step) {
      const idx = i * 4;
      const px = particles[idx];
      const py = particles[idx + 1];
      const vx = particles[idx + 2];
      const vy = particles[idx + 3];

      const speed = Math.sqrt(vx * vx + vy * vy);
      const hue = HUE_CENTER + (i % HUE_SPREAD) - HUE_SPREAD / 2 + speed * 3;
      const alpha = 0.15 + Math.min(speed * 0.08, 0.35);
      const size = PARTICLE_SIZE + speed * 0.3;

      ctx.fillStyle = `hsla(${hue}, ${SATURATION}%, ${LIGHTNESS}%, ${alpha})`;
      ctx.beginPath();
      ctx.arc(px, py, size, 0, 6.2832);
      ctx.fill();
    }

    // Draw subtle connecting lines for nearby particles (sparse sample)
    ctx.strokeStyle = `hsla(${HUE_CENTER}, ${SATURATION}%, ${LIGHTNESS}%, 0.02)`;
    ctx.lineWidth = 0.5;
    for (let i = 0; i < N; i += 15) {
      const idx = i * 4;
      const px = particles[idx];
      const py = particles[idx + 1];
      for (let j = i + 15; j < N && j < i + 120; j += 15) {
        const jdx = px - particles[j * 4];
        const jdy = py - particles[j * 4 + 1];
        const dsq = jdx * jdx + jdy * jdy;
        if (dsq < 900) {
          const a = 0.02 * (1 - Math.sqrt(dsq) / 30);
          ctx.strokeStyle = `hsla(${HUE_CENTER}, ${SATURATION}%, ${LIGHTNESS}%, ${a})`;
          ctx.beginPath();
          ctx.moveTo(px, py);
          ctx.lineTo(particles[j * 4], particles[j * 4 + 1]);
          ctx.stroke();
        }
      }
    }
  }

  function frame() {
    update();
    draw();
    requestAnimationFrame(frame);
  }

  // Events
  window.addEventListener('mousemove', (e) => {
    target.x = e.clientX;
    target.y = e.clientY;
    mouseActive = true;
  });

  window.addEventListener('touchmove', (e) => {
    e.preventDefault();
    const t = e.touches[0];
    target.x = t.clientX;
    target.y = t.clientY;
    mouseActive = true;
  }, { passive: false });

  window.addEventListener('mouseleave', () => {
    mouseActive = false;
    target.x = width / 2;
    target.y = height / 2;
  });

  window.addEventListener('resize', resize);

  // Init
  resize();
  requestAnimationFrame(frame);
})();
</script>
