<body>
<script type="importmap">
{
  "imports": {
    "three": "https://esm.sh/three@0.162.0",
    "three/addons/": "https://esm.sh/three@0.162.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js';
import { PMREMGenerator } from 'three/addons/environments/PMREMGenerator.js';
import { RoomEnvironment } from 'three/addons/environments/RoomEnvironment.js';

// ─── Renderer ───────────────────────────────────────────────────────────
const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: false });
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
renderer.shadowMap.enabled = true;
document.body.appendChild(renderer.domElement);

// ─── Scene ──────────────────────────────────────────────────────────────
const scene = new THREE.Scene();

// Background gradient via a full-screen quad behind everything
const bgCanvas = document.createElement('canvas');
bgCanvas.width = 512; bgCanvas.height = 512;
const ctx = bgCanvas.getContext('2d');
const grad = ctx.createRadialGradient(256, 256, 0, 256, 256, 400);
grad.addColorStop(0, '#0a0a18');
grad.addColorStop(0.5, '#060610');
grad.addColorStop(1, '#020208');
ctx.fillStyle = grad;
ctx.fillRect(0, 0, 512, 512);
const bgTexture = new THREE.CanvasTexture(bgCanvas);
scene.background = bgTexture;

// ─── Camera ─────────────────────────────────────────────────────────────
const camera = new THREE.PerspectiveCamera(50, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0, 1, 8);

// ─── Controls ───────────────────────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.05;
controls.autoRotate = true;
controls.autoRotateSpeed = 0.4;
controls.enableZoom = false;
controls.enablePan = false;
controls.target.set(0, 0, 0);

// ─── Environment Map (RoomEnvironment + PMREM) ──────────────────────────
const pmremGenerator = new PMREMGenerator(renderer);
pmremGenerator.compileEquirectangularShader();
const envMap = pmremGenerator.fromScene(new RoomEnvironment(), 0.04).texture;
scene.environment = envMap;

// ─── Lighting ───────────────────────────────────────────────────────────
// Key light — warm
const keyLight = new THREE.DirectionalLight(0xffeedd, 3.5);
keyLight.position.set(5, 8, 6);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024, 1024);
scene.add(keyLight);

// Fill light — cool
const fillLight = new THREE.DirectionalLight(0x8888ff, 1.2);
fillLight.position.set(-6, 2, -4);
scene.add(fillLight);

// Subtle rim / back light
const rimLight = new THREE.PointLight(0xff6688, 1.0, 20);
rimLight.position.set(0, -3, -6);
scene.add(rimLight);

// Very soft ambient
const ambientLight = new THREE.AmbientLight(0x111122, 0.3);
scene.add(ambientLight);

// ─── Crystals ───────────────────────────────────────────────────────────
const crystalData = [
  { radius: 0.7,  color: new THREE.Color(0x44aaff), orbitR: 2.2, orbitSpeed: 0.35, tiltX: 0.5,  tiltY: 0.3,  phase: 0.0   },
  { radius: 0.5,  color: new THREE.Color(0xff66aa), orbitR: 1.8, orbitSpeed: -0.45, tiltX: -0.3, tiltY: 0.7,  phase: 1.0   },
  { radius: 0.9,  color: new THREE.Color(0xaaffcc), orbitR: 3.0, orbitSpeed: 0.25,  tiltX: 0.8,  tiltY: -0.2, phase: 2.0   },
  { radius: 0.4,  color: new THREE.Color(0xffcc44), orbitR: 1.4, orbitSpeed: -0.55, tiltX: -0.6, tiltY: 0.5,  phase: 3.2   },
  { radius: 0.65, color: new THREE.Color(0x88ccff), orbitR: 2.6, orbitSpeed: 0.40,  tiltX: 0.2,  tiltY: -0.8, phase: 4.1   },
  { radius: 0.55, color: new THREE.Color(0xff88cc), orbitR: 2.0, orbitSpeed: -0.30, tiltX: -0.4, tiltY: 0.4,  phase: 5.5   },
  { radius: 0.75, color: new THREE.Color(0xccffaa), orbitR: 3.3, orbitSpeed: 0.20,  tiltX: 0.7,  tiltY: 0.6,  phase: 6.0   },
];

const crystals = [];

crystalData.forEach((data, i) => {
  const geometry = new THREE.IcosahedronGeometry(data.radius, 1);

  const material = new THREE.MeshPhysicalMaterial({
    color: data.color,
    metalness: 0.05,
    roughness: 0.08,
    transmission: 0.92,
    thickness: 1.5,
    ior: 1.5,
    clearcoat: 0.3,
    clearcoatRoughness: 0.1,
    envMapIntensity: 1.5,
    transparent: true,
    opacity: 0.95,
    side: THREE.DoubleSide,
  });

  const mesh = new THREE.Mesh(geometry, material);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  mesh.userData = data;
  scene.add(mesh);
  crystals.push(mesh);
});

// ─── Post-processing: Unreal Bloom ──────────────────────────────────────
const composer = new EffectComposer(renderer);
composer.addPass(new THREE.RenderPass(scene, camera));

const bloomPass = new UnrealBloomPass(
  new THREE.Vector2(window.innerWidth, window.innerHeight),
  0.6,   // strength
  0.5,   // radius
  0.75   // threshold
);
composer.addPass(bloomPass);

// ─── Animation ──────────────────────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);

  const t = clock.getElapsedTime();
  const dt = clock.getDelta();

  // Animate crystals
  crystals.forEach((mesh) => {
    const d = mesh.userData;
    const angle = t * d.orbitSpeed + d.phase;

    // Orbital position
    const x = Math.sin(angle) * d.orbitR;
    const z = Math.cos(angle) * d.orbitR;
    const y = Math.sin(t * 0.5 + d.phase) * 0.8 + Math.sin(t * 0.3 + d.phase * 2) * 0.3;

    mesh.position.set(x, y, z);

    // Gentle rotation
    mesh.rotation.x += 0.005 + d.tiltX * 0.003;
    mesh.rotation.y += 0.007 + d.tiltY * 0.003;
    mesh.rotation.z += 0.002;

    // Slight scale pulsing
    const pulse = 1.0 + Math.sin(t * 1.2 + d.phase) * 0.03;
    mesh.scale.setScalar(pulse);
  });

  // Animate rim light color
  rimLight.color.setHSL((t * 0.05) % 1, 0.6, 0.5);

  controls.update();
  composer.render();
}

animate();

// ─── Resize ─────────────────────────────────────────────────────────────
window.addEventListener('resize', () => {
  const w = window.innerWidth;
  const h = window.innerHeight;

  camera.aspect = w / h;
  camera.updateProjectionMatrix();

  renderer.setSize(w, h);
  composer.setSize(w, h);
  bloomPass.resolution.set(w, h);
});
</script>
</body>
</html>
