  { radius: 0.5,  color: new THREE.Color(0xff66aa), orbitR: 1.8, orbitSpeed: -0.45, tiltX: -0.3, tiltY: 0.7,  phase: 1.0   },
  { radius: 0.9,  color: new THREE.Color(0xaaffcc), orbitR: 3.0, orbitSpeed: 0.25,  tiltX: 0.8,  tiltY: -0.2, phase: 2.0   },
  { radius: 0.4,  color: new THREE.Color(0xffcc44), orbitR: 1.4, orbitSpeed: -0.55, tiltX: -0.6, tiltY: 0.5,  phase: 3.2   },
  { radius: 0.65, color: new THREE.Color(0x88ccff), orbitR: 2.6, orbitSpeed: 0.40,  tiltX: 0.2,  tiltY: -0.8, phase: 4.1   },
  { radius: 0.55, color: new THREE.Color(0xff88cc), orbitR: 2.0, orbitSpeed: -0.30, tiltX: -0.4, tiltY: 0.4,  phase: 5.5   },
  { radius: 0.75, color: new THREE.Color(0xccffaa), orbitR: 3.3, orbitSpeed: 0.20,  tiltX: 0.7,  tiltY: 0.6,  phase: 6.0   },
];

const crystals = [];

crystalData.forEach((data, i) => {
  const geometry = new THREE.IcosahedronGeometry(data.radius, 1);

  const material = new THREE.MeshPhysicalMaterial({
    color: data.color,
    metalness: 0.05,
    roughness: 0.08,
    transmission: 0.92,
    thickness: 1.5,
    ior: 1.5,
    clearcoat: 0.3,
    clearcoatRoughness: 0.1,
    envMapIntensity: 1.5,
    transparent: true,
    opacity: 0.95,
    side: THREE.DoubleSide,
  });

  const mesh = new THREE.Mesh(geometry, material);
  mesh.castShadow = true;
  mesh.receiveShadow = true;
  mesh.userData = data;
  scene.add(mesh);
  crystals.push(mesh);
});

// ─── Post-processing: Unreal Bloom ──────────────────────────────────────
const composer = new EffectComposer(renderer);
composer.addPass(new THREE.RenderPass(scene, camera));

const bloomPass = new UnrealBloomPass(
  new THREE.Vector2(window.innerWidth, window.innerHeight),
  0.6,   // strength
  0.5,   // radius
  0.75   // threshold
);
composer.addPass(bloomPass);

// ─── Animation ──────────────────────────────────────────────────────────
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);

  const t = clock.getElapsedTime();
  const dt = clock.getDelta();

  // Animate crystals
  crystals.forEach((mesh) => {
    const d = mesh.userData;
    const angle = t * d.orbitSpeed + d.phase;

    // Orbital position
    const x = Math.sin(angle) * d.orbitR;
    const z = Math.cos(angle) * d.orbitR;
    const y = Math.sin(t * 0.5 + d.phase) * 0.8 + Math.sin(t * 0.3 + d.phase * 2) * 0.3;

    mesh.position.set(x, y, z);

    // Gentle rotation
    mesh.rotation.x += 0.005 + d.tiltX * 0.003;
    mesh.rotation.y += 0.007 + d.tiltY * 0.003;
    mesh.rotation.z += 0.002;

    // Slight scale pulsing
    const pulse = 1.0 + Math.sin(t * 1.2 + d.phase) * 0.03;
    mesh.scale.setScalar(pulse);
  });

  // Animate rim light color
  rimLight.color.setHSL((t * 0.05) % 1, 0.6, 0.5);

  controls.update();
  composer.render();
}

animate();

// ─── Resize ─────────────────────────────────────────────────────────────
window.addEventListener('resize', () => {
  const w = window.innerWidth;
  const h = window.innerHeight;

  camera.aspect = w / h;
  camera.updateProjectionMatrix();

  renderer.setSize(w, h);
  composer.setSize(w, h);
  bloomPass.resolution.set(w, h);
});
</script>
</body>
</html>
