        scene_signed(p + vec3(e, 0, 0), t) - scene_signed(p - vec3(e, 0, 0), t),
        scene_signed(p + vec3(0, e, 0), t) - scene_signed(p - vec3(0, e, 0), t),
        scene_signed(p + vec3(0, 0, e), t) - scene_signed(p - vec3(0, 0, e), t)
    );
    return normalize(n);
}

float scene_signed(vec3 p, float t) {
    float sr = 0.55 + 0.18 * sin(t * 0.7);
    vec3 sp = vec3(0.7 * sin(t * 0.5), 0.8 + 0.3 * sin(t * 1.1), 0.7 * cos(t * 0.4));
    float s = sdSphere(p - sp, sr);

    vec2 ta = vec2(0.6 + 0.1 * sin(t * 0.6), 0.18 + 0.04 * sin(t * 1.3));
    vec3 tp = vec3(0.5 * cos(t * 0.35), 0.4 + 0.25 * sin(t * 0.9), 0.5 * sin(t * 0.35));
    float tor = sdTorus(p - tp, ta);

    float obj = opSmoothUnion(s, tor, 0.3);
    float gnd = -p.y;
    return min(obj, gnd);
}

float calcAO(vec3 p, vec3 n) {
    float ao = 0.0;
    float t = iTime;
    for (int i = 1; i <= 5; i++) {
        float dist = 0.04 * float(i);
        float d = scene_signed(p + n * dist, t);
        ao += (dist - d) / dist;
    }
    return clamp(1.0 - 0.5 * ao / 5.0, 0.0, 1.0);
}

// ── Main ────────────────────────────────────────────────

void main() {
    vec2 uv = (gl_FragCoord.xy - 0.5 * iResolution.xy) / iResolution.y;

    // Camera
    float camDist = 4.5;
    float camAngleH = iTime * 0.25;
    float camAngleV = 0.3 + 0.15 * sin(iTime * 0.18);
    vec3 ro = vec3(
        camDist * sin(camAngleV) * cos(camAngleH),
        camDist * cos(camAngleV),
        camDist * sin(camAngleV) * sin(camAngleH)
    );
    vec3 target = vec3(0.0);
    vec3 fwd = normalize(target - ro);
    vec3 right = normalize(cross(fwd, vec3(0, 1, 0)));
    vec3 up = cross(right, fwd);
    vec3 rd = normalize(fwd + uv.x * right + uv.y * up);

    // Raymarch
    float t = march(ro, rd, 20.0);

    // Background sky
    vec3 col = mix(vec3(0.05, 0.05, 0.12), vec3(0.25, 0.35, 0.55), uv.y + 0.5);
    col += 0.15 * vec3(1.0, 0.6, 0.3) * max(0.0, dot(rd, normalize(vec3(1, 0.3, 0.5))));

    // Hit?
    if (t < 20.0) {
        vec3 p = ro + rd * t;
        vec3 n = calcNormal(p);

        // Light
        float lt = iTime;
        vec3 lightDir = normalize(vec3(
            0.6 * cos(lt * 0.6),
            0.7 + 0.2 * sin(lt * 0.8),
            0.6 * sin(lt * 0.6)
        ));

        // Object color
        float checker_val = step(0.5, fract(floor(p.x * 2.0) + floor(p.z * 2.0)));
        bool isGround = (p.y < 0.001);

        vec3 albedo;
        if (isGround) {
            albedo = mix(vec3(0.12, 0.1, 0.08), vec3(0.22, 0.2, 0.18), checker_val);
        } else {
            float hue = 0.5 + 0.5 * sin(iTime * 0.5 + p.x * 2.0);
            albedo = mix(vec3(0.85, 0.25, 0.1), vec3(0.1, 0.55, 0.9), hue);
        }

        // Lambert
        float diff = max(dot(n, lightDir), 0.0);

        // Specular (Blinn-Phong)
        vec3 h = normalize(lightDir - rd);
        float spec = pow(max(dot(n, h), 0.0), 32.0) * 0.4;

        // Ambient
        float ambient = 0.12;

        // AO
        float ao = calcAO(p, n);

        // Fog
        float fogFactor = 1.0 - exp(-t * 0.06);

        // Composite
        col = albedo * (ambient + diff * ao) + spec * vec3(1.0, 0.95, 0.9) * ao;
        col = mix(col, vec3(0.15, 0.18, 0.25), fogFactor);
    }

    // Tone mapping + gamma
    col = col / (1.0 + col);
    col = pow(col, vec3(1.0 / 2.2));

    // Subtle vignette
    vec2 vuv = gl_FragCoord.xy / iResolution.xy;
    float vig = 1.0 - 0.3 * length(vuv - 0.5);
    col *= vig;

    fragColor = vec4(col, 1.0);
}
`;

  /* ─── Helpers ───────────────────────────────────────────── */
  const errorPre = document.getElementById("error-log");

  function logError(msg) {
    console.error(msg);
    errorPre.textContent = msg;
    errorPre.style.display = "block";
  }

  function compileShader(gl, type, src) {
    const s = gl.createShader(type);
    gl.shaderSource(s, src);
    gl.compileShader(s);
    const ok = gl.getShaderParameter(s, gl.COMPILE_STATUS);
    if (!ok) {
      const log = gl.getShaderInfoLog(s);
      logError("Shader compilation failed:\n" + log);
      gl.deleteShader(s);
      return null;
    }
    return s;
  }

  function createProgram(gl, vs, fs) {
    const p = gl.createProgram();
    gl.attachShader(p, vs);
    gl.attachShader(p, fs);
    gl.linkProgram(p);
    const ok = gl.getProgramParameter(p, gl.LINK_STATUS);
    if (!ok) {
      const log = gl.getProgramInfoLog(p);
      logError("Program linking failed:\n" + log);
      gl.deleteProgram(p);
      return null;
    }
    return p;
  }

  /* ─── Init ──────────────────────────────────────────────── */
  const gl = canvas.getContext("webgl2", { antialias: true, alpha: false });
  if (!gl) {
    logError("WebGL2 not supported.");
    return;
  }

  const vs = compileShader(gl, gl.VERTEX_SHADER, VERT_SRC);
  if (!vs) return;
  const fs = compileShader(gl, gl.FRAGMENT_SHADER, FRAG_SRC);
  if (!fs) return;
  const prog = createProgram(gl, vs, fs);
  if (!prog) return;

  gl.useProgram(prog);

  // Fullscreen quad: two triangles, clip-space coords
  const buf = gl.createBuffer();
  gl.bindBuffer(gl.ARRAY_BUFFER, buf);
  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([
    -1, -1,
     1, -1,
    -1,  1,
     1,  1,
  ]), gl.STATIC_DRAW);

  const aPos = gl.getAttribLocation(prog, "aPos");
  gl.enableVertexAttribArray(aPos);
  gl.vertexAttribPointer(aPos, 2, gl.FLOAT, false, 0, 0);

  // Uniforms
  const uTime = gl.getUniformLocation(prog, "iTime");
  const uRes  = gl.getUniformLocation(prog, "iResolution");

  // Handle DPR + resize
  function resize() {
    const dpr = window.devicePixelRatio || 1;
    const w = Math.floor(canvas.clientWidth  * dpr);
    const h = Math.floor(canvas.clientHeight * dpr);
    if (canvas.width  !== w || canvas.height !== h) {
      canvas.width  = w;
      canvas.height = h;
      gl.viewport(0, 0, w, h);
    }
  }
  window.addEventListener("resize", resize);
  resize();

  // Draw
  const t0 = performance.now();
  function frame() {
    const t = (performance.now() - t0) * 0.001;
    gl.uniform1f(uTime, t);
    gl.uniform2f(uRes, canvas.width, canvas.height);
    gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);
    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);

})();
</script>
</body>
</html>
```

**What this does:**

1. **WebGL2 context** — created on a full-window `<canvas>` with DPR-aware sizing and a `resize` listener.

2. **Inline shaders** — vertex shader renders a fullscreen quad; fragment shader contains the entire raymarcher.

3. **SDF scene** — `opSmoothUnion` blends a **sphere** (morphing radius and position via sine waves) and a **torus** (morphing major/minor radius and position) together. A **checker-pattern ground plane** (`-y`) provides a floor.

4. **Lighting** — Lambert diffuse + Blinn-Phong specular + ambient occlusion (5-ray estimate) + fog. One directional light orbits the scene via `iTime`.

5. **Camera** — slowly orbits around the origin at a moderate distance, tilted slightly downward.

6. **Tone mapping** — Reinhard + gamma correction + subtle vignette.

7. **Error handling** — if either shader fails to compile or the program fails to link, the info log is written to the JavaScript console **and** displayed in an on-page `<pre>` element at the bottom of the screen.

