<body>
<canvas id="c"></canvas>
<div id="info">
  Drag to pull cloth &middot; Right-click / Shift+click to tear
</div>
<script>
(function () {
  "use strict";

  /* ── constants ── */
  const COLS      = 24;
  const ROWS      = 16;
  const GRAVITY   = 0.45;
  const DAMPING   = 0.985;
  const ITERATIONS = 6;
  const DRAG_RADIUS = 80;
  const DRAG_STIFFNESS = 0.85;
  const REST_SCALE = 0.65;
  const TENSION = 1.0;
  const BEND_STIFFNESS = 0.6;

  /* ── canvas setup ── */
  const canvas = document.getElementById("c");
  const ctx    = canvas.getContext("2d");

  let dpr, W, H;
  function resize() {
    dpr = window.devicePixelRatio || 1;
    W = window.innerWidth;
    H = window.innerHeight;
    canvas.width  = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width  = W + "px";
    canvas.style.height = H + "px";
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  }
  window.addEventListener("resize", resize);
  resize();

  /* ── particle & constraint data ── */
  const N = COLS * ROWS;

  const px  = new Float32Array(N);
  const py  = new Float32Array(N);
  const ox  = new Float32Array(N);
  const oy  = new Float32Array(N);
  const pinned = new Uint8Array(N);

  /* structural constraints  */
  const cType  = new Uint8Array(N * 4);  // 0=structural, 1=bend
  const cDist  = new Float32Array(N * 4);
  const cI     = new Int16Array(N * 4);
  const cJ     = new Int16Array(N * 4);
  const cActive = new Uint8Array(N * 4);

  let constraintCount = 0;
  const MAX_CONSTRAINTS = N * 4;

  function addConstraint(i, j, d, type) {
    if (constraintCount >= MAX_CONSTRAINTS) return;
    const k = constraintCount;
    cI[k] = i; cJ[k] = j;
    cDist[k] = d;
    cType[k] = type;
    cActive[k] = 1;
    constraintCount++;
  }

  /* ── build grid ── */
  function build() {
    const spacing = Math.min(W, H) * 0.028;
    const restLen = spacing * REST_SCALE;
    const totalW  = (COLS - 1) * restLen;
    const totalH  = (ROWS - 1) * restLen;
    const oxStart = (W - totalW) / 2;
    const oyStart = H * 0.12;

    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        const idx = r * COLS + c;
        const x = oxStart + c * restLen;
        const y = oyStart + r * restLen;
        px[idx] = x; py[idx] = y;
        ox[idx] = x; oy[idx] = y;
        pinned[idx] = (r === 0) ? 1 : 0;
      }
    }

    /* structural */
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS - 1; c++) {
        const idx = r * COLS + c;
        addConstraint(idx, idx + 1, restLen, 0);
      }
    }
    for (let r = 0; r < ROWS - 1; r++) {
      for (let c = 0; c < COLS; c++) {
        const idx = r * COLS + c;
        addConstraint(idx, idx + COLS, restLen, 0);
      }
    }

    /* bend / shear */
    for (let r = 0; r < ROWS - 1; r++) {
      for (let c = 0; c < COLS - 1; c++) {
        const idx = r * COLS + c;
        addConstraint(idx, idx + COLS + 1, restLen * Math.SQRT2, 1);
        addConstraint(idx + 1, idx + COLS, restLen * Math.SQRT2, 1);
      }
    }
  }
  build();

  /* ── mouse state ── */
  const mouse = { x: 0, y: 0, down: false, right: false, dragIdx: -1, dragOffX: 0, dragOffY: 0 };

  function findNearest(mx, my) {
    let best = -1, bestD = DRAG_RADIUS * DRAG_RADIUS;
    for (let i = 0; i < N; i++) {
      const dx = mx - px[i], dy = my - py[i];
      const d = dx * dx + dy * dy;
      if (d < bestD) { bestD = d; best = i; }
    }
    return best;
  }

  function findNearestConstraint(mx, my) {
    let best = -1, bestD = DRAG_RADIUS * DRAG_RADIUS;
    for (let k = 0; k < constraintCount; k++) {
      if (!cActive[k]) continue;
      const i = cI[k], j = cJ[k];
      const mx2 = (px[i] + px[j]) * 0.5, my2 = (py[i] + py[j]) * 0.5;
      const dx = mx - mx2, dy = my - my2;
      const d = dx * dx + dy * dy;
      if (d < bestD) { bestD = d; best = k; }
    }
    return best;
  }

  canvas.addEventListener("mousedown", function (e) {
    const mx = e.clientX, my = e.clientY;
    mouse.x = mx; mouse.y = my;

    if (e.button === 2 || e.shiftKey) {
      mouse.right = true;
      const ci = findNearestConstraint(mx, my);
      if (ci >= 0) { cActive[ci] = 0; }
      e.preventDefault();
      return;
    }

    mouse.down = true;
    const idx = findNearest(mx, my);
    if (idx >= 0) {
      mouse.dragIdx = idx;
      mouse.dragOffX = px[idx] - mx;
      mouse.dragOffY = py[idx] - my;
    }
  });

  canvas.addEventListener("mousemove", function (e) {
    mouse.x = e.clientX;
    mouse.y = e.clientY;
  });

  canvas.addEventListener("mouseup", function (e) {
    if (e.button === 2) { mouse.right = false; return; }
    mouse.down = false;
    mouse.dragIdx = -1;
  });

  canvas.addEventListener("contextmenu", function (e) { e.preventDefault(); });

  /* touch support */
  canvas.addEventListener("touchstart", function (e) {
    e.preventDefault();
    const t = e.touches[0];
    mouse.x = t.clientX; mouse.y = t.clientY;
    mouse.down = true;
    const idx = findNearest(t.clientX, t.clientY);
    if (idx >= 0) {
      mouse.dragIdx = idx;
      mouse.dragOffX = px[idx] - t.clientX;
      mouse.dragOffY = py[idx] - t.clientY;
    }
  }, { passive: false });

  canvas.addEventListener("touchmove", function (e) {
    e.preventDefault();
    const t = e.touches[0];
    mouse.x = t.clientX; mouse.y = t.clientY;
  }, { passive: false });

  canvas.addEventListener("touchend", function () {
    mouse.down = false;
    mouse.dragIdx = -1;
  });

  /* ── simulation ── */
  function simulate() {
    /* 1. Verlet integration */
    for (let i = 0; i < N; i++) {
      if (pinned[i]) continue;
      const vx = (px[i] - ox[i]) * DAMPING;
      const vy = (py[i] - oy[i]) * DAMPING;
      ox[i] = px[i];
      oy[i] = py[i];
      px[i] += vx;
      py[i] += vy + GRAVITY;
    }

    /* 2. Mouse drag */
    if (mouse.down && mouse.dragIdx >= 0 && !pinned[mouse.dragIdx]) {
      const targetX = mouse.x + mouse.dragOffX;
      const targetY = mouse.y + mouse.dragOffY;
      px[mouse.dragIdx] = px[mouse.dragIdx] * (1 - DRAG_STIFFNESS) + targetX * DRAG_STIFFNESS;
      py[mouse.dragIdx] = py[mouse.dragIdx] * (1 - DRAG_STIFFNESS) + targetY * DRAG_STIFFNESS;
    }

    /* 3. Constraint solver */
    for (let iter = 0; iter < ITERATIONS; iter++) {
      for (let k = 0; k < constraintCount; k++) {
        if (!cActive[k]) continue;
        const i = cI[k], j = cJ[k];
        const d = cDist[k];
        const dx = px[j] - px[i];
        const dy = py[j] - py[i];
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 1e-6) continue;
        const diff = (dist - d) / dist;
        const stiff = cType[k] === 0 ? TENSION : BEND_STIFFNESS;

        if (pinned[i] && pinned[j]) continue;
        if (pinned[i]) {
          px[j] -= dx * diff * stiff;
          py[j] -= dy * diff * stiff;
        } else if (pinned[j]) {
          px[i] += dx * diff * stiff;
          py[i] += dy * diff * stiff;
        } else {
          const h = diff * stiff * 0.5;
          px[i] += dx * h; py[i] += dy * h;
          px[j] -= dx * h; py[j] -= dy * h;
        }
      }

      /* mouse pin during drag */
      if (mouse.down && mouse.dragIdx >= 0 && !pinned[mouse.dragIdx]) {
        const targetX = mouse.x + mouse.dragOffX;
        const targetY = mouse.y + mouse.dragOffY;
        const dx2 = targetX - px[mouse.dragIdx];
        const dy2 = targetY - py[mouse.dragIdx];
        px[mouse.dragIdx] += dx2 * DRAG_STIFFNESS;
        py[mouse.dragIdx] += dy2 * DRAG_STIFFNESS;
      }
    }

    /* 4. Boundary clamping */
    for (let i = 0; i < N; i++) {
      if (pinned[i]) continue;
      const margin = 10;
      if (px[i] < margin)  px[i] = margin;
      if (px[i] > W - margin) px[i] = W - margin;
      if (py[i] > H - margin) { py[i] = H - margin; oy[i] = py[i] - (py[i] - oy[i]) * 0.3; }
    }
  }

  /* ── render ── */
  function render() {
    ctx.clearRect(0, 0, W, H);

    /* subtle ambient glow behind cloth */
    const glow = ctx.createRadialGradient(W * 0.5, H * 0.45, 0, W * 0.5, H * 0.45, H * 0.6);
    glow.addColorStop(0, "rgba(30, 40, 80, 0.15)");
    glow.addColorStop(1, "rgba(0, 0, 0, 0)");
    ctx.fillStyle = glow;
    ctx.fillRect(0, 0, W, H);

    /* ── draw quads ── */
    for (let r = 0; r < ROWS - 1; r++) {
      for (let c = 0; c < COLS - 1; c++) {
        const i00 = r * COLS + c;
        const i10 = i00 + 1;
        const i01 = i00 + COLS;
        const i11 = i00 + COLS + 1;

        const x00 = px[i00], y00 = py[i00];
        const x10 = px[i10], y10 = py[i10];
        const x01 = px[i01], y01 = py[i01];
        const x11 = px[i11], y11 = py[i11];

        /* velocity-based color */
        const v00 = Math.sqrt((px[i00] - ox[i00]) ** 2 + (py[i00] - oy[i00]) ** 2);
        const v10 = Math.sqrt((px[i10] - ox[i10]) ** 2 + (py[i10] - oy[i10]) ** 2);
        const v01 = Math.sqrt((px[i01] - ox[i01]) ** 2 + (py[i01] - oy[i01]) ** 2);
        const v11 = Math.sqrt((px[i11] - ox[i11]) ** 2 + (py[i11] - oy[i11]) ** 2);
        const avgV = (v00 + v10 + v01 + v11) * 0.25;
        const t = Math.min(1, avgV / 18);

        const cx = (x00 + x10 + x01 + x11) * 0.25;
        const cy = (y00 + y10 + y01 + y11) * 0.25;

        const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, 200);
        const r1 = Math.round(25 + t * 120);
        const g1 = Math.round(35 + t * 160);
        const b1 = Math.round(70 + t * 180);
        grad.addColorStop(0, `rgba(${r1},${g1},${b1},0.22)`);
        grad.addColorStop(1, `rgba(${Math.round(r1 * 0.5)},${Math.round(g1 * 0.5)},${Math.round(b1 * 0.5)},0.04)`);

        ctx.beginPath();
        ctx.moveTo(x00, y00);
        ctx.lineTo(x10, y10);
        ctx.lineTo(x11, y11);
        ctx.lineTo(x01, y01);
        ctx.closePath();
        ctx.fillStyle = grad;
        ctx.fill();
      }
    }

    /* ── draw lines ── */
    ctx.lineWidth = 0.7;
    ctx.lineCap = "round";

    for (let k = 0; k < constraintCount; k++) {
      if (!cActive[k]) continue;
      const i = cI[k], j = cJ[k];
      const dx = px[j] - px[i];
      const dy = py[j] - py[i];
      const len = Math.sqrt(dx * dx + dy * dy);
      const rest = cDist[k];
      const strain = Math.abs(len - rest) / rest;

      /* structural vs bend */
      const isStruct = cType[k] === 0;
      const baseAlpha = isStruct ? 0.35 : 0.12;
      const tensionColor = Math.min(1, strain * 3);

      const rr = Math.round(60 + tensionColor * 140);
      const gg = Math.round(80 + tensionColor * 80);
      const bb = Math.round(140 - tensionColor * 60);
      const aa = baseAlpha + tensionColor * 0.3;

      ctx.strokeStyle = `rgba(${rr},${gg},${bb},${aa})`;
      ctx.beginPath();
      ctx.moveTo(px[i], py[i]);
      ctx.lineTo(px[j], py[j]);
      ctx.stroke();
    }

    /* ── pinned nodes ── */
    ctx.fillStyle = "#8899cc";
    for (let c = 0; c < COLS; c++) {
      const i = c;
      ctx.beginPath();
      ctx.arc(px[i], py[i], 2.5, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  /* ── main loop ── */
  function frame() {
    simulate();
    render();
    requestAnimationFrame(frame);
  }

  requestAnimationFrame(frame);

})();
</script>
</body>
