<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Radial Audio Visualizer</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { width: 100%; height: 100%; overflow: hidden; background: #000; }
  canvas { display: block; width: 100%; height: 100%; }
  #overlay {
    position: fixed; inset: 0;
    display: flex; align-items: center; justify-content: center;
    background: rgba(0,0,0,0.92);
    color: #fff; font: 400 2.4rem/1 system-ui, sans-serif;
    cursor: pointer; z-index: 10;
    transition: opacity 0.6s ease-out;
    user-select: none;
  }
  #overlay.fade { opacity: 0; pointer-events: none; }
  #overlay span { animation: pulse 2s ease-in-out infinite; }
  @keyframes pulse {
    0%,100% { opacity: 0.4; }
    50% { opacity: 1; }
  }
</style>
</head>
<body>
<canvas id="c"></canvas>
<div id="overlay"><span>&#9654; Click to start</span></div>
<script>
(() => {
  const canvas = document.getElementById('c');
  const ctx = canvas.getContext('2d');
  const overlay = document.getElementById('overlay');
  const NUM_BARS = 64;

  let audioCtx, analyser, dataArray, isLive, animId;
  let bassTarget = 1, bassCurrent = 1;

  // ─── Canvas setup ──────────────────────────────────
  function resize() {
    const dpr = window.devicePixelRatio || 1;
    canvas.width = window.innerWidth * dpr;
    canvas.height = window.innerHeight * dpr;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  }
  window.addEventListener('resize', resize);
  resize();

  // ─── Start handler (must run from gesture) ─────────
  function start(e) {
    overlay.classList.add('fade');
    setTimeout(() => overlay.style.display = 'none', 700);
    initAudio();
  }
  overlay.addEventListener('click', start);
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); start(e); }
  });

  // ─── Audio initialisation ──────────────────────────
  function initAudio() {
    try {
      audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    } catch { return; }

    analyser = audioCtx.createAnalyser();
    analyser.fftSize = 1024;
    analyser.smoothingTimeConstant = 0.82;
    dataArray = new Uint8Array(analyser.frequencyBinCount);
    isLive = false;

    navigator.mediaDevices.getUserMedia({ audio: true })
      .then(stream => {
        const src = audioCtx.createMediaStreamSource(stream);
        src.connect(analyser);
        isLive = true;
      })
      .catch(() => {
        // Permission denied – synthesise gentle audio
        const osc = audioCtx.createOscillator();
        const gain = audioCtx.createGain();
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1, audioCtx.currentTime);
        osc.frequency.linearRampToValueAtTime(1.5, audioCtx.currentTime + 2);
        osc.frequency.linearRampToValueAtTime(1, audioCtx.currentTime + 4);
        gain.gain.value = 0.6;
        osc.connect(gain).connect(analyser);
        osc.start();

        // Slow noise via periodic white-noise bursts
        const bufSize = audioCtx.sampleRate * 0.4;
        const buf = audioCtx.createBuffer(1, bufSize, audioCtx.sampleRate);
        const data = buf.getChannelData(0);
        for (let i = 0; i < bufSize; i++) data[i] = Math.random() * 2 - 1;

        const noiseSrc = audioCtx.createBufferSource();
        noiseSrc.buffer = buf;
        noiseSrc.loop = true;
        const nGain = audioCtx.createGain();
        nGain.gain.value = 0.18;
        noiseSrc.connect(nGain).connect(analyser);
        noiseSrc.start();
      });

    animId = requestAnimationFrame(frame);
  }

  // ─── Rendering ─────────────────────────────────────
  function frame() {
    if (!analyser) return;
    analyser.getByteFrequencyData(dataArray);

    const W = window.innerWidth, H = window.innerHeight;
    const cx = W / 2, cy = H / 2;
    const maxR = Math.min(cx, cy);

    const ringR = maxR * 0.52;
    const barMin = ringR * 0.62;
    const barMax = ringR * 1.18;

    // Bass: average of lowest 6 frequency bins
    let bass = 0;
    for (let i = 0; i < 6; i++) bass += dataArray[i];
    bass = bass / (6 * 255);
    bassTarget = 1 + bass * 0.28;
    bassCurrent += (bassTarget - bassCurrent) * 0.09;

    ctx.fillStyle = 'rgba(0,0,0,0.14)';
    ctx.fillRect(0, 0, W, H);

    const angleStep = (Math.PI * 2) / NUM_BARS;
    const binStep = Math.floor(dataArray.length / NUM_BARS);

    for (let i = 0; i < NUM_BARS; i++) {
      let sum = 0;
      for (let b = 0; b < binStep; b++) sum += dataArray[i * binStep + b];
      const val = (sum / binStep) / 255;

      const a1 = i * angleStep - Math.PI / 2;
      const a2 = (i + 1) * angleStep - Math.PI / 2;

      const inner = barMin * bassCurrent;
      const outer = (barMin + (barMax - barMin) * val) * bassCurrent;

      const hue = (i / NUM_BARS) * 300 + 15;

      ctx.beginPath();
      ctx.arc(cx, cy, outer, a1, a2);
      ctx.arc(cx, cy, inner, a2, a1, true);
      ctx.closePath();
      ctx.fillStyle = `hsla(${hue}, 92%, 58%, 0.82)`;
      ctx.fill();
    }

    // Centre glow
    const g = ctx.createRadialGradient(cx, cy, 0, cx, cy, ringR * 0.42);
    g.addColorStop(0, 'rgba(255,255,255,0.035)');
    g.addColorStop(1, 'rgba(255,255,255,0)');
    ctx.fillStyle = g;
    ctx.fillRect(cx - ringR * 0.42, cy - ringR * 0.42, ringR * 0.84, ringR * 0.84);

    animId = requestAnimationFrame(frame);
  }
})();
</script>
</body>
</html>
